#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#define MAX_H 100005
#define MAX_N 1005
#define MAX_M 1005
#define MAX_T 1000005
#define INF 1000000000000000000LL

int compare(const void *a, const void *b) {
    return (*(long long *)a - *(long long *)b);
}

int main() {
    int N, M, H;
    long long T[MAX_H], C[MAX_H];
    long long min_cost = INF;
    long long cost = 0;
    long long mask;
    int i, j, k;
    scanf("%d %d %d", &N, &M, &H);
    for (i = 0; i < H; i++) {
        scanf("%lld %lld", &T[i], &C[i]);
    }
    for (mask = 0; mask < (1LL << H); mask++) {
        cost = 0;
        int can_paint = 1;
        for (i = 0; i < N; i++) {
            for (j = 0; j < M; j++) {
                int painted = 0;
                for (k = 0; k < H; k++) {
                    if ((mask & (1LL << k)) != 0 && T[k] > 0) {
                        T[k]--;
                        painted = 1;
                        break;
                    }
                }
                if (!painted) {
                    can_paint = 0;
                    break;
                }
            }
            if (!can_paint) break;
        }
        if (can_paint) {
            for (i = 0; i < H; i++) {
                if ((mask & (1LL << i)) != 0) {
                    cost += C[i] * (N * M - T[i]);
                }
            }
            if (cost < min_cost) {
                min_cost = cost;
            }
        }
    }
    if (min_cost == INF) {
        printf("Impossible\n");
    } else {
        printf("%lld\n", min_cost);
    }
    return 0;
}

